import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const Section = styled.section`
  padding: 120px 60px;
  background: #FFFDF4;
  position: relative;

  @media (max-width: 768px) {
    padding: 80px 30px;
  }
`;

const FloralCorner = styled.div`
  position: absolute;
  font-size: 4rem;
  color: #D4AF37;
  opacity: 0.08;

  &.top-left {
    top: 40px;
    left: 40px;
  }

  &.bottom-right {
    bottom: 40px;
    right: 40px;
    transform: rotate(180deg);
  }
`;

const SectionHeader = styled.div`
  text-align: center;
  margin-bottom: 80px;
`;

const SectionSubtitle = styled(motion.p)`
  font-family: 'Montserrat', sans-serif;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: #D4AF37;
  margin-bottom: 15px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 15px;

  &:before, &:after {
    content: '&#10047;';
    font-size: 0.6rem;
  }
`;

const SectionTitle = styled(motion.h2)`
  font-family: 'Cormorant Garamond', serif;
  font-size: 3rem;
  font-weight: 300;
  color: #800020;
  letter-spacing: 4px;
  text-transform: uppercase;

  @media (max-width: 768px) {
    font-size: 2rem;
  }
`;

const CollectionGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 25px;
  max-width: 1400px;
  margin: 0 auto;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const CollectionCard = styled(motion.div)`
  position: relative;
  height: 520px;
  overflow: hidden;
  cursor: pointer;

  &:nth-child(1) {
    grid-row: span 2;
    height: 100%;
  }

  @media (max-width: 768px) {
    height: 420px;

    &:nth-child(1) {
      grid-row: span 1;
    }
  }
`;

const CardImage = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: ${props => props.bg};
  background-size: cover;
  background-position: center;
  transition: transform 0.8s ease;

  ${CollectionCard}:hover & {
    transform: scale(1.08);
  }
`;

const CardOverlay = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(to top, rgba(128, 0, 32, 0.85) 0%, rgba(128, 0, 32, 0.2) 40%, transparent 70%);
  transition: background 0.5s ease;

  ${CollectionCard}:hover & {
    background: linear-gradient(to top, rgba(128, 0, 32, 0.95) 0%, rgba(128, 0, 32, 0.4) 60%, rgba(128, 0, 32, 0.2) 100%);
  }
`;

const CardFloral = styled.div`
  position: absolute;
  top: 20px;
  right: 20px;
  font-size: 1.5rem;
  color: #D4AF37;
  opacity: 0.4;
  transition: all 0.4s ease;

  ${CollectionCard}:hover & {
    opacity: 0.8;
    transform: rotate(15deg) scale(1.2);
  }
`;

const CardContent = styled.div`
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 40px;
  color: #FFFDF4;
`;

const CardSeason = styled.span`
  font-family: 'Montserrat', sans-serif;
  font-size: 0.6rem;
  font-weight: 500;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: #D4AF37;
  display: block;
  margin-bottom: 12px;
`;

const CardTitle = styled.h3`
  font-family: 'Cormorant Garamond', serif;
  font-size: 2rem;
  font-weight: 400;
  letter-spacing: 3px;
  margin-bottom: 15px;
`;

const CardDescription = styled.p`
  font-family: 'Cormorant Garamond', serif;
  font-size: 1rem;
  font-weight: 300;
  line-height: 1.8;
  font-style: italic;
  opacity: 0;
  transform: translateY(20px);
  transition: all 0.5s ease;

  ${CollectionCard}:hover & {
    opacity: 0.9;
    transform: translateY(0);
  }
`;

const ViewButton = styled.span`
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-family: 'Montserrat', sans-serif;
  font-size: 0.65rem;
  font-weight: 500;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: #D4AF37;
  margin-top: 20px;
  padding-bottom: 5px;
  border-bottom: 1px solid transparent;
  opacity: 0;
  transform: translateY(20px);
  transition: all 0.5s ease 0.1s;

  ${CollectionCard}:hover & {
    opacity: 1;
    transform: translateY(0);
    border-bottom-color: #D4AF37;
  }
`;

const collections = [
  {
    season: "Editorial",
    title: "Editorial Styling",
    description: "Fashion storytelling for magazines and publications.",
    bg: "url('/flammarion40.jpeg')",
    flower: "&#10047;"
  },
  {
    season: "Lookbook",
    title: "Lookbook Styling",
    description: "Creating cohesive visual narratives for brands.",
    bg: "url('/flammarion9.jpeg')",
    flower: "&#10048;"
  },
  {
    season: "Personal",
    title: "Personal Styling",
    description: "Helping individuals discover their unique style.",
    bg: "url('/flammarion25.jpeg')",
    flower: "&#10046;"
  },
  {
    season: "Creative",
    title: "Creative Direction",
    description: "Concept development and visual direction for shoots.",
    bg: "url('/flammarion55.jpeg')",
    flower: "&#10049;"
  },
  {
    season: "Wardrobe",
    title: "Wardrobe Consulting",
    description: "Building functional and stylish wardrobes.",
    bg: "url('/flammarion6.jpeg')",
    flower: "&#10047;"
  }
];

function Collections() {
  return (
    <Section id="collections">
      <FloralCorner className="top-left">&#10047;</FloralCorner>
      <FloralCorner className="bottom-right">&#10047;</FloralCorner>

      <SectionHeader>
        <SectionSubtitle
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          What I Do
        </SectionSubtitle>
        <SectionTitle
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.1 }}
        >
          Services
        </SectionTitle>
      </SectionHeader>

      <CollectionGrid>
        {collections.map((collection, index) => (
          <CollectionCard
            key={index}
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, delay: index * 0.1 }}
          >
            <CardImage bg={collection.bg} />
            <CardOverlay />
            <CardFloral dangerouslySetInnerHTML={{ __html: collection.flower }} />
            <CardContent>
              <CardSeason>{collection.season}</CardSeason>
              <CardTitle>{collection.title}</CardTitle>
              <CardDescription>{collection.description}</CardDescription>
              <ViewButton>Learn More &#8594;</ViewButton>
            </CardContent>
          </CollectionCard>
        ))}
      </CollectionGrid>
    </Section>
  );
}

export default Collections;
